.darma-loader-darma-custom-600 {
   width: 110px;
   height: 30px;
   color: var(--loader-color, #b45309);
   display: flex;
   background: linear-gradient(currentColor 0 0) left /30px 10px, linear-gradient(currentColor 0 0) right/30px 10px, conic-gradient(from -136deg at 15px 50%,#0000 ,currentColor 1deg 90deg,#0000 91deg) 30px 0/100% 100%, conic-gradient(from 44deg at calc(100% - 15px) 50%,#0000 ,currentColor 1deg 90deg,#0000 91deg) calc(100% - 30px) 0/100% 100%;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-600-l7 .5s infinite alternate;
}
.darma-loader-darma-custom-600:before  {
  content: "";
   flex: 1;
   background: inherit;
   transform: rotate(90deg);
}
@keyframes darma-loader-darma-custom-600-l7  {
  90%,100%{width:93px}
}

